async def run_seed():
    mongo_url = os.environ['MONGO_URL']
    db_name = os.environ['DB_NAME']
    client = AsyncIOMotorClient(mongo_url)
    db = client[db_name]
    now = datetime.now(timezone.utc).isoformat()

    # 1. Clear old CPR data
    await db.cpr_clients.delete_many({})
    await db.cpr_elisabeth_clients.delete_many({})
    await db.cpr_payment_records.delete_many({})
    await db.cpr_shar_payouts.delete_many({})
    await db.notary_waiver_log.delete_many({})
    await db.cpr_mailing_expenses.delete_many({})
    print("[SEED] Cleared old CPR data")

    # 2. Seed payments
    for p in PAYMENTS:
        doc = {"id": str(uuid.uuid4()), **p, "created_at": now, "created_by": "seed"}
        await db.cpr_shar_payouts.insert_one(doc)
    print(f"[SEED] {len(PAYMENTS)} payments inserted")

    # 3. Seed notary waivers
    for w in NOTARY_WAIVERS:
        doc = {"id": str(uuid.uuid4()), **w, "recorded_at": now, "created_by": "seed"}
        await db.notary_waiver_log.insert_one(doc)
    print(f"[SEED] {len(NOTARY_WAIVERS)} notary waivers inserted")

    # 4. Seed Legacy CPR clients
    for c in LEGACY_CPR_CLIENTS:
        doc = {"id": str(uuid.uuid4()), **c, "created_at": now, "updated_at": now, "created_by": "seed"}
        await db.cpr_clients.insert_one(doc)
    print(f"[SEED] {len(LEGACY_CPR_CLIENTS)} Legacy CPR clients inserted")

    # 5. Seed Shar Active clients with financial calculations
    for c in SHAR_ACTIVE_CLIENTS:
        doc = {"id": str(uuid.uuid4()), **c, "created_at": now, "updated_at": now, "created_by": "seed"}
        financials = calculate_shar_active(doc)
        doc.update(financials)
        await db.cpr_clients.insert_one(doc)
    print(f"[SEED] {len(SHAR_ACTIVE_CLIENTS)} Shar Active clients inserted (with financials)")

    # 6. Seed New Credlocity clients with financial calculations
    for c in NEW_CREDLOCITY_CLIENTS:
        doc = {"id": str(uuid.uuid4()), **c, "created_at": now, "updated_at": now, "created_by": "seed"}
        financials = calculate_new_credlocity(doc)
        doc.update(financials)
        await db.cpr_clients.insert_one(doc)
    print(f"[SEED] {len(NEW_CREDLOCITY_CLIENTS)} New Credlocity clients inserted (with financials)")

    # 7. Verify William Peden Kendal
    william = await db.cpr_clients.find_one({"full_name": "William Peden Kendal", "category": "shar_active"}, {"_id": 0})
    if william:
        expected = {"jan_feb_gross": 198.10, "jan_feb_net": 158.30, "mar_jun_gross": 25.54, "mar_jun_net": 6.99, "shar_total": 161.79, "joe_total": 3.49, "grand_total": 165.28}
        all_pass = True
        for k, v in expected.items():
            actual = william.get(k, 0)
            match = abs(actual - v) < 0.001
            if not match:
                all_pass = False
            print(f"  {k}: expected={v}, actual={actual} [{'PASS' if match else 'FAIL'}]")
        print(f"\n{'VERIFICATION PASSED' if all_pass else 'VERIFICATION FAILED'}")
    else:
        print("ERROR: William Peden Kendal not found!")

    # Summary
    total = len(LEGACY_CPR_CLIENTS) + len(SHAR_ACTIVE_CLIENTS) + len(NEW_CREDLOCITY_CLIENTS)
    print(f"\n[SEED COMPLETE] {total} clients total ({len(LEGACY_CPR_CLIENTS)} Legacy + {len(SHAR_ACTIVE_CLIENTS)} Shar Active + {len(NEW_CREDLOCITY_CLIENTS)} New Credlocity)")

    client.close()


if __name__ == "__main__":
    asyncio.run(run_seed())
